          const wellId = `${rows[r]}${c}`;
          // First column is controls, last column is blanks, rest are samples or standards
          let wellType: string;
          if (c === 1) wellType = "control";
          else if (c === 12) wellType = "blank";
          else if (r === 0 || r === 7) wellType = "standard";
