const FullFeatured = () => <TdpSearch
    columns={columns}
    filters={filters}
    defaultQuery="sample"
    defaultSort={{ field: "createdAt", order: "desc" }}
    pageSize={15}
    onSearch={() => {}} />;

const WithFilters = () => <TdpSearch
    columns={[
      { key: "id", header: "ID" },
      { key: "filePath", header: "File Path", sortable: true },
      { key: "sourceType", header: "Source Type", sortable: true },
      { key: "status", header: "Status", sortable: true },
      { key: "fileSize", header: "Size", sortable: true },
      { key: "createdAt", header: "Created", sortable: true },
    ]}
    filters={filters}
    defaultQuery="sample"
    pageSize={10} />;

const CustomRendering = () => <TdpSearch
    columns={[
      {
        key: "id",
        header: "ID",
        width: "100px",
        render: (value) => (
          <code style={{ fontSize: 12, color: "var(--muted-foreground, #6b7280)", letterSpacing: "0.02em" }}>{value}</code>
        ),
      },
      {
        key: "filePath",
        header: "File Path",
        sortable: true,
        render: (value) => (
          <span
            style={{
              fontFamily: "'Fira Code', 'Source Code Pro', monospace",
              fontSize: 13,
              color: "var(--primary, #1d4ed8)",
              textDecoration: "underline",
              textDecorationColor: "var(--primary, #bfdbfe)",
              textUnderlineOffset: 2,
              cursor: "pointer",
            }}
          >
            {value}
          </span>
        ),
      },
      {
        key: "sourceType",
        header: "Source Type",
        sortable: true,
        render: (value) => {
          const colorMap: Record<string, { bg: string; fg: string; border: string }> = {
            "instrument-data": { bg: "var(--background)", fg: "var(--foreground)", border: "#bfdbfe" },
            "manual-upload": { bg: "var(--background)", fg: "var(--foreground)", border: "#fde68a" },
            "pipeline-output": { bg: "var(--background)", fg: "var(--foreground)", border: "#bbf7d0" },
          };
          const colors = colorMap[value] ?? { bg: "var(--background)", fg: "var(--foreground)", border: "#d1d5db" };
          return (
            <span
              style={{
                display: "inline-block",
                padding: "3px 10px",
                borderRadius: 12,
                fontSize: 12,
                fontWeight: 600,
                backgroundColor: colors.bg,
                color: colors.fg,
                border: `1px solid ${colors.border}`,
                whiteSpace: "nowrap",
              }}
            >
              {(value ?? "unknown").replace(/-/g, " ")}
            </span>
          );
        },
      },
      {
        key: "status",
        header: "Status",
        sortable: true,
        render: (value) => {
          const statusMap: Record<string, { bg: string; fg: string; dot: string }> = {
            processed: { bg: "#f0fdf4", fg: "#15803d", dot: "#22c55e" },
            pending: { bg: "#fffbeb", fg: "#b45309", dot: "#f59e0b" },
            failed: { bg: "#fef2f2", fg: "#b91c1c", dot: "#ef4444" },
          };
          const s = statusMap[value] ?? { bg: "#f3f4f6", fg: "#374151", dot: "#9ca3af" };
          return (
            <span
              style={{
                display: "inline-flex",
                alignItems: "center",
                gap: 6,
                padding: "3px 10px",
                borderRadius: 12,
                fontSize: 12,
                fontWeight: 600,
                backgroundColor: s.bg,
                color: s.fg,
              }}
            >
              <span style={{ width: 7, height: 7, borderRadius: "50%", backgroundColor: s.dot, flexShrink: 0 }} />
              {value}
            </span>
          );
        },
      },
      {
        key: "fileSize",
        header: "Size",
        align: "right" as const,
        sortable: true,
        render: (value) => {
          if (!value) return <span>—</span>;
          const mb = value / 1024 / 1024;
          const maxMb = 6;
          const pct = Math.min((mb / maxMb) * 100, 100);
          return (
            <span style={{ display: "inline-flex", alignItems: "center", gap: 8, minWidth: 120 }}>
              <span
                style={{
                  flex: 1,
                  height: 6,
                  borderRadius: 3,
                  backgroundColor: "var(--muted, #f3f4f6)",
                  overflow: "hidden",
                }}
              >
                <span
                  style={{
                    display: "block",
                    height: "100%",
                    width: `${pct}%`,
                    borderRadius: 3,
                    backgroundColor: pct > 75 ? "#f59e0b" : "var(--primary, #3b82f6)",
                    transition: "width 0.3s ease",
                  }}
                />
              </span>
              <span style={{ fontSize: 12, fontWeight: 500, fontVariantNumeric: "tabular-nums" }}>
                {mb.toFixed(1)} MB
              </span>
            </span>
          );
        },
      },
      {
        key: "createdAt",
        header: "Created",
        sortable: true,
        render: (value) => {
          if (!value) return "—";
          const d = new Date(value);
          return (
            <span style={{ fontSize: 13 }}>
              {d.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}
              <span style={{ marginLeft: 6, fontSize: 12 }}>
                {d.toLocaleTimeString("en-US", { hour: "2-digit", minute: "2-digit" })}
              </span>
            </span>
          );
        },
      },
    ] as TdpSearchColumn[]}
    defaultQuery="experiment"
    defaultSort={{ field: "createdAt", order: "desc" }}
    pageSize={10} />;

const CustomSearchBar = () => <TdpSearch
    columns={columns}
    defaultQuery="sample"
    pageSize={10}
    renderSearchBar={(props) => <DemoSearchBar {...props} />} />;

